import { AsyncPipe, CurrencyPipe, DatePipe } from '@angular/common';
import { Component, inject } from '@angular/core';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { combineLatest, map, tap } from 'rxjs';
import { AuctionPublicService } from '../../services/auction-public.service';
import { LanguageService } from '../../services/language.service';
import { SeoService } from '../../services/seo.service';
import { SiteService } from '../../services/site.service';

@Component({
  selector: 'app-auctions-page',
  standalone: true,
  imports: [AsyncPipe, RouterLink, CurrencyPipe, DatePipe],
  templateUrl: './auctions.page.html',
  styleUrl: './auctions.page.sass'
})
export class AuctionsPage {
  private readonly auctionService = inject(AuctionPublicService);
  private readonly languageService = inject(LanguageService);
  private readonly siteService = inject(SiteService);
  private readonly seoService = inject(SeoService);
  private readonly route = inject(ActivatedRoute);

  protected readonly vm$ = combineLatest([
    this.siteService.getSiteConfig(),
    this.siteService.getPagesConfig(),
    this.auctionService.getAuctions()
  ]).pipe(
    map(([siteConfig, pagesConfig, auctions]) => {
      const language = this.languageService.getRouteLanguage(this.route.snapshot);
      const heroImage = pagesConfig.auctions?.heroImage
        || auctions[0]?.artwork.images.main.sources.large
        || siteConfig.seo.defaultOgImage;

      return {
        siteConfig,
        auctions,
        language,
        heroImage
      };
    }),
    tap(({ siteConfig, language, heroImage }) => {
      this.seoService.applyLocalizedAlternates(
        siteConfig.domain,
        this.route.snapshot,
        undefined,
        siteConfig.defaultLanguage
      );

      this.seoService.applyPageMetadata({
        title: language === 'it' ? `Aste | ${siteConfig.artistName}` : `Auctions | ${siteConfig.artistName}`,
        description:
          language === 'it'
            ? `Aste pubbliche e opere in dialogo con il collezionismo sul sito di ${siteConfig.artistName}.`
            : `Public auctions and works in dialogue with collectors on ${siteConfig.artistName}'s website.`,
        url: `${siteConfig.domain}${this.languageService.buildLocalizedPath(language, 'auctions')}`,
        image: `${siteConfig.domain}${heroImage}`,
        siteName: siteConfig.artistName,
        language
      });
    })
  );

  protected getAuctionPath(language: 'it' | 'en', slug: string): string[] {
    return language === 'it' ? ['/it/aste', slug] : ['/en/auctions', slug];
  }

  protected getStatusLabel(language: 'it' | 'en', status: 'live' | 'upcoming' | 'closed'): string {
    if (status === 'live') {
      return language === 'it' ? 'Asta in corso' : 'Auction live';
    }

    if (status === 'upcoming') {
      return language === 'it' ? 'Asta in apertura' : 'Auction opening soon';
    }

    return language === 'it' ? 'Asta conclusa' : 'Auction closed';
  }
}
